content.problemStatement:
&nbsp;

Chef is fan of pairs and he likes all things that come in pairs. He even has a doll collection in which the dolls come in pairs. One day while going through his collection he found that there are odd number of dolls. Someone had stolen a doll!!!  

Help chef find which type of doll is missing..

code.C++:
#include<iostream>

using namespace std;
int main()
{
    int T;
    cin >> T;
    while (T--)
    {
        int N;
        cin >> N;
        int Arr[N];
        for (int i = 0; i < N; i++)
        {
            cin >> Arr[i];
        }
        int ans = 0;
        for (int i = 0; i < N; i++)
        {
            ans ^= Arr[i];
        }
        cout << ans << endl;
    }
}

code.C:
#include <stdio.h>

int main()
{
    int T;
    scanf("%d", &T);  // Reading the number of test cases
    while (T--)
    {
        int N;
        scanf("%d", &N);  // Reading the size of the array
        int Arr[N];

        // Reading array elements
        for (int i = 0; i < N; i++)
        {
            scanf("%d", &Arr[i]);
        }

        // XOR operation to find the answer
        int ans = 0;
        for (int i = 0; i < N; i++)
        {
            ans ^= Arr[i];
        }

        // Output the result
        printf("%d\n", ans);
    }
    return 0;
}

code.Java:
import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef
{
    public static void main (String[] args) throws java.lang.Exception
    {
        // Input handling
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();  // Number of test cases

        while (T-- > 0) {
            int N = sc.nextInt();  // Size of the array
            int[] Arr = new int[N];

            // Reading array elements
            for (int i = 0; i < N; i++) {
                Arr[i] = sc.nextInt();
            }

            // XOR operation to find the answer
            int ans = 0;
            for (int i = 0; i < N; i++) {
                ans ^= Arr[i];
            }

            // Output the result
            System.out.println(ans);
        }

        sc.close();  // Closing the scanner
    }
}
